277→            vAcc4 = __riscv_vd4dots_vv_i32m2(vAcc4, vpA_i8m2, vpB3_i8m2, vl);
278→            vAcc5 = __riscv_vd4dots_vv_i32m2(vAcc5, vpA2_i8m2, vpB3_i8m2, vl);
279→
280→            vAcc6 = __riscv_vd4dots_vv_i32m2(vAcc6, vpA_i8m2, vpB4_i8m2, vl);
281→            vAcc7 = __riscv_vd4dots_vv_i32m2(vAcc7, vpA2_i8m2, vpB4_i8m2, vl);
282→        }
283→
284→        vl = __riscv_vsetvl_e32m2(col_src1);    //note the avl here
285→        vint32m1_t vSum0 = __riscv_vredsum(vAcc0, vZero, vl);
286→        vint32m1_t vSum1 = __riscv_vredsum(vAcc1, vZero, vl);
287→        vint32m1_t vSum2 = __riscv_vredsum(vAcc2, vZero, vl);
288→        vint32m1_t vSum3 = __riscv_vredsum(vAcc3, vZero, vl);
289→        vint32m1_t vSum4 = __riscv_vredsum(vAcc4, vZero, vl);
290→        vint32m1_t vSum5 = __riscv_vredsum(vAcc5, vZero, vl);
291→        vint32m1_t vSum6 = __riscv_vredsum(vAcc6, vZero, vl);
292→        vint32m1_t vSum7 = __riscv_vredsum(vAcc7, vZero, vl);
293→
294→        vl = __riscv_vsetvl_e32m1(2);     //2: 2 acc
295→        vSum0 = __riscv_vslideup(vSum0, vSum1, 1, vl);
296→        vSum2 = __riscv_vslideup(vSum2, vSum3, 1, vl);
297→        vSum4 = __riscv_vslideup(vSum4, vSum5, 1, vl);
298→        vSum6 = __riscv_vslideup(vSum6, vSum7, 1, vl);
299→
300→        //1st shift of 2-stage shift
301→        vSum0 = __riscv_vsra(vSum0, pre_rshift, vl);
302→        vSum2 = __riscv_vsra(vSum2, pre_rshift, vl);
303→        vSum4 = __riscv_vsra(vSum4, pre_rshift, vl);
304→        vSum6 = __riscv_vsra(vSum6, pre_rshift, vl);
305→
306→        vSum0 = __riscv_vmul(vSum0, out_scale, vl);
307→        vSum2 = __riscv_vmul(vSum2, out_scale, vl);
308→        vSum4 = __riscv_vmul(vSum4, out_scale, vl);
309→        vSum6 = __riscv_vmul(vSum6, out_scale, vl);
310→
311→        vSum0 = __riscv_vadd(vSum0, NN_ROUND(post_rshift), vl);
312→        vSum2 = __riscv_vadd(vSum2, NN_ROUND(post_rshift), vl);
313→        vSum4 = __riscv_vadd(vSum4, NN_ROUND(post_rshift), vl);
314→        vSum6 = __riscv_vadd(vSum6, NN_ROUND(post_rshift), vl);
315→
316→        //saturate into 8-bits
317→        vl = __riscv_vsetvl_e16mf2(2);     //2: 2 acc
318→        vint16mf2_t vSum0_i16mf2 = __riscv_vnsra(vSum0, post_rshift, vl);
319→        vint16mf2_t vSum2_i16mf2 = __riscv_vnsra(vSum2, post_rshift, vl);
320→        vint16mf2_t vSum4_i16mf2 = __riscv_vnsra(vSum4, post_rshift, vl);
321→        vint16mf2_t vSum6_i16mf2 = __riscv_vnsra(vSum6, post_rshift, vl);
322→        vl = __riscv_vsetvl_e8mf4(2);     //2: 2 acc
323→        vint8mf4_t vSum0_i8mf4 = __riscv_vnclip(vSum0_i16mf2, 0, __RISCV_VXRM_RNU, vl);
324→        vint8mf4_t vSum2_i8mf4 = __riscv_vnclip(vSum2_i16mf2, 0, __RISCV_VXRM_RNU, vl);
325→        vint8mf4_t vSum4_i8mf4 = __riscv_vnclip(vSum4_i16mf2, 0, __RISCV_VXRM_RNU, vl);
326→        vint8mf4_t vSum6_i8mf4 = __riscv_vnclip(vSum6_i16mf2, 0, __RISCV_VXRM_RNU, vl);
327→
328→        //store the results
329→        __riscv_vse8(out, vSum0_i8mf4, vl);
330→        __riscv_vse8(pOut2, vSum2_i8mf4, vl);
331→        __riscv_vse8(pOut3, vSum4_i8mf4, vl);
332→        __riscv_vse8(pOut4, vSum6_i8mf4, vl);
333→        out += vl;
334→        pOut2 += vl;
335→        pOut3 += vl;
336→        pOut4 += vl;
337→    }
338→
339→    out += out_tensor_ch * 3;
340→
341→    return out;
342→#elif defined(ENA_NDS_V5_VEC_DOT_PROD)
343→    unsigned long vl;
344→    unsigned long rowCnt = out_tensor_ch >> 2;
345→    q7_t *pOut2 = out + out_tensor_ch;
346→    q7_t *pOut3 = out + out_tensor_ch * 2;
347→    q7_t *pOut4 = out + out_tensor_ch * 3;
348→
349→    const q7_t *pA = src1;
350→
351→#if (__clang__)
352→    register const long zero asm ("x0") = 0;
353→#else
354→    register const long zero asm ("x0");
355→#endif
356→    NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
357→    NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0x0);     //keep zero for redsum
358→
359→    while(rowCnt > 0)
360→    {
361→        // setup pointers for A
362→        const q7_t *pA2 = pA + col_src1;
363→        const q7_t *pA3 = pA + col_src1 * 2;
364→        const q7_t *pA4 = pA + col_src1 * 3;
365→        // setup pointers for B
366→        const q7_t *pB = src2;
367→        const q7_t *pB2 = pB + col_src1;
368→        const q7_t *pB3 = pB + col_src1 * 2;
369→        const q7_t *pB4 = pB + col_src1 * 3;
370→
371→        NDS_VEC_VSETVLI(vl, zero, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
372→
373→        //init
374→        //clear v8~v23 (keep multiplication results)
375→        NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0x0);
376→        NDS_VEC_VAND_VI(NDS_VEC_V16, NDS_VEC_V16, 0x0);
377→
378→        unsigned long colCnt = col_src1;
379→        while(colCnt > 0)
380→        {
381→            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
382→            //load src1 and src2
383→            NDS_VEC_VLB_V(NDS_VEC_V0, pA);
384→            NDS_VEC_VLB_V(NDS_VEC_V1, pA2);
385→            NDS_VEC_VLB_V(NDS_VEC_V2, pA3);
386→            NDS_VEC_VLB_V(NDS_VEC_V3, pA4);
387→
388→            NDS_VEC_VLB_V(NDS_VEC_V4, pB);
389→            NDS_VEC_VLB_V(NDS_VEC_V5, pB2);
390→            NDS_VEC_VLB_V(NDS_VEC_V6, pB3);
391→            NDS_VEC_VLB_V(NDS_VEC_V7, pB4);
392→
393→            //bump pointers and update loop counter
394→            colCnt -= vl;
395→            pA += vl;
396→            pA2 += vl;
397→            pA3 += vl;
398→            pA4 += vl;
399→            pB += vl;
400→            pB2 += vl;
401→            pB3 += vl;
402→            pB4 += vl;
403→
404→            //set the proper avl/SEW/LMUL values for vd4dot
405→            vl >>= 2;
406→            NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
407→
408→            //acc += src1 * src2
409→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V8, NDS_VEC_V0, NDS_VEC_V4);
410→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V9, NDS_VEC_V1, NDS_VEC_V4);
411→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V10, NDS_VEC_V2, NDS_VEC_V4);
412→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V11, NDS_VEC_V3, NDS_VEC_V4);
413→
414→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V12, NDS_VEC_V0, NDS_VEC_V5);
415→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V13, NDS_VEC_V1, NDS_VEC_V5);
416→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V14, NDS_VEC_V2, NDS_VEC_V5);
417→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V15, NDS_VEC_V3, NDS_VEC_V5);
418→
419→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V16, NDS_VEC_V0, NDS_VEC_V6);
420→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V17, NDS_VEC_V1, NDS_VEC_V6);
421→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V18, NDS_VEC_V2, NDS_VEC_V6);
422→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V19, NDS_VEC_V3, NDS_VEC_V6);
