730→    {
731→        /* left part */
732→        for (i_out_x = 0; i_out_x < pad; i_out_x++)
733→        {
734→            /* This part implements the im2col function */
735→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
736→            {
737→                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
738→                {
739→                    if (i_ker_x < 0 || i_ker_x >= in_tensor_dim)
740→                    {
741→                        memset(pBuffer, 0, sizeof(q15_t)*in_tensor_ch);
742→                    }
743→                    else
744→                    {
745→                        nn_dup_s8_s16_reordered
746→                        ((q7_t *) in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
747→                    }
748→                    pBuffer += in_tensor_ch;
749→                }
750→            }
751→
752→            if (pBuffer == in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
753→            {
754→                pOut =
755→                    nn_mat_mul_kernel_q7_q15_q7_reordered_2sft(ker_weight,
756→                                                               in_tmp_buf,
757→                                                               out_tensor_ch,
758→                                                               in_tensor_ch * ker_dim * ker_dim,
759→                                                               pre_rshift,
760→                                                               out_scale,
761→                                                               post_rshift,
762→                                                               pOut);
763→                /* counter reset */
764→                pBuffer = in_tmp_buf;
765→            }
766→        }
767→
768→        /* mid part */
769→        for (; i_out_x < out_tensor_dim - pad; i_out_x++)
770→        {
771→            /* This part implements the im2col function */
772→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
773→            {
774→                nn_dup_s8_s16_reordered((q7_t *) in_tensor + (i_ker_y * in_tensor_dim + i_out_x * stride - pad) * in_tensor_ch, pBuffer, in_tensor_ch * ker_dim);
775→                pBuffer += in_tensor_ch * ker_dim;
776→            }
777→
778→            if (pBuffer == in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
779→            {
780→                pOut =
781→                    nn_mat_mul_kernel_q7_q15_q7_reordered_2sft(ker_weight,
782→                                                               in_tmp_buf,
783→                                                               out_tensor_ch,
784→                                                               in_tensor_ch * ker_dim * ker_dim,
785→                                                               pre_rshift,
786→                                                               out_scale,
787→                                                               post_rshift,
788→                                                               pOut);
789→                /* counter reset */
790→                pBuffer = in_tmp_buf;
791→            }
792→        }
793→
794→        /* right part */
795→        for (; i_out_x < out_tensor_dim; i_out_x++)
796→        {
797→            /* This part implements the im2col function */
798→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
799→            {
800→                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
801→                {
802→                    if (i_ker_x < 0 || i_ker_x >= in_tensor_dim)
803→                    {
804→                        memset(pBuffer, 0, sizeof(q15_t)*in_tensor_ch);
805→                    }
806→                    else
807→                    {
808→                        nn_dup_s8_s16_reordered
809→                        ((q7_t *) in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
810→                    }
811→                    pBuffer += in_tensor_ch;
812→                }
813→            }
814→
815→            if (pBuffer == in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
816→            {
817→                pOut =
818→                    nn_mat_mul_kernel_q7_q15_q7_reordered_2sft(ker_weight,
819→                                                               in_tmp_buf,
820→                                                               out_tensor_ch,
821→                                                               in_tensor_ch * ker_dim * ker_dim,
822→                                                               pre_rshift,
823→                                                               out_scale,
824→                                                               post_rshift,
825→                                                               pOut);
826→                /* counter reset */
827→                pBuffer = in_tmp_buf;
828→            }
829→        }
830→    }
831→
832→    for (; i_out_y < out_tensor_dim; i_out_y++)
833→    {
834→        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
835→        {
836→            /* This part implements the im2col function */
837→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
838→            {
839→                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
840→                {
841→                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim || i_ker_x < 0 || i_ker_x >= in_tensor_dim)
842→                    {
843→                        memset(pBuffer, 0, sizeof(q15_t)*in_tensor_ch);
844→                    }
845→                    else
846→                    {
847→                        nn_dup_s8_s16_reordered
848→                        ((q7_t *) in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
849→                    }
850→                    pBuffer += in_tensor_ch;
851→                }
852→            }
853→
854→            if (pBuffer == in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
855→            {
856→                pOut =
857→                    nn_mat_mul_kernel_q7_q15_q7_reordered_2sft(ker_weight,
858→                                                               in_tmp_buf,
859→                                                               out_tensor_ch,
860→                                                               in_tensor_ch * ker_dim * ker_dim,
861→                                                               pre_rshift,
862→                                                               out_scale,
863→                                                               post_rshift,
864→                                                               pOut);
865→                /* counter reset */
866→                pBuffer = in_tmp_buf;
867→            }
868→        }
869→    }
870→
871→    /* check if there is left-over for compute */
872→    if (pBuffer != in_tmp_buf)
873→    {
874→        const q7_t *pA = ker_weight;
875→        int       i;
876→
877→        for (i = 0; i < out_tensor_ch; i++)
878→        {
879→            q31_t     sum = 0;
880→            q15_t    *pB = in_tmp_buf;
881→            /* each time it process 4 entries */
882→            uint16_t  colCnt = in_tensor_ch * ker_dim * ker_dim >> 2;
883→
884→            while (colCnt)
885→            {
886→                q31_t     inA1, inA2;
887→                q31_t     inB1, inB2;
888→
889→                pA = (q7_t *) read_and_pad_reordered((void *)pA, &inA1, &inA2);
890→
891→                inB1 = *__SIMD32(pB)++;
892→                sum = NDS_DSP_KMADA(sum, inA1, inB1);
893→                inB2 = *__SIMD32(pB)++;
894→                sum = NDS_DSP_KMADA(sum, inA2, inB2);
895→
896→                colCnt--;
897→            }
898→            //since in_tensor_ch is multiple of 4 (input constraints), the
899→            //following codes will not be reached
900→            // colCnt = in_tensor_ch * ker_dim * ker_dim & 0x3;
901→            // while (colCnt)
902→            // {
903→            //     q7_t      inA1 = *pA++;
904→            //     q15_t     inB1 = *pB++;
905→            //     sum += inA1 * inB1;
906→            //     colCnt--;
907→            // }
908→            sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
909→            *pOut++ = NDS_DSP_SATS((sum >> post_rshift), 8);
910→        }
911→    }
912→#else
913→    uint16_t  i, j, k, l, m, n;
914→    int       conv_out;
915→    long in_row, in_col;
916→
917→    for (i = 0; i < out_tensor_ch; i++)
918→    {
919→        for (j = 0; j < out_tensor_dim; j++)
920→        {
921→            for (k = 0; k < out_tensor_dim; k++)
922→            {
923→                conv_out = 0;
924→                for (m = 0; m < ker_dim; m++)
925→                {
926→                    for (n = 0; n < ker_dim; n++)
927→                    {
928→                        // if-for implementation
929→                        in_row = stride * j + m - pad;
930→                        in_col = stride * k + n - pad;
931→                        if (in_row >= 0 && in_col >= 0 && in_row < in_tensor_dim && in_col < in_tensor_dim)
932→                        {
933→                            for (l = 0; l < in_tensor_ch; l++)
934→                            {
935→                                conv_out +=
936→                                    in_tensor[(in_row * in_tensor_dim + in_col) * in_tensor_ch + l]
937→                                    * ker_weight[i * in_tensor_ch * ker_dim * ker_dim + (m * ker_dim + n) * in_tensor_ch + l];
938→                            }
939→                        }
940→                    }
941→                }
942→                conv_out = (conv_out >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
943→                out_tensor[i + (j * out_tensor_dim + k) * out_tensor_ch] = NDS_ISA_SATS((conv_out >> post_rshift), 8);
944→            }
945→        }
946→    }
947→#endif  //ENA_DSP_ISA
948→#endif  //ENA_EMPTY_FUN
949→
950→    /* Return to application */
951→    return 0;
952→}
